const events = $input.all();
const currentDate = $json.body.date || new Date().toISOString().split('T')[0];

// Lọc các event đang active (start_date <= today <= end_date)
const activeEvents = events.filter(event => {
  const startDate = new Date(event.start_date);
  const endDate = new Date(event.end_date);
  const today = new Date(currentDate);

  // Set time to 00:00:00 for date comparison
  startDate.setHours(0, 0, 0, 0);
  endDate.setHours(23, 59, 59, 999);
  today.setHours(0, 0, 0, 0);

  return today >= startDate && today <= endDate;
});

// Lấy event có discount cao nhất
const bestEvent = activeEvents.reduce((best, current) => {
  if (!best) return current;
  return current.discount_percent > best.discount_percent ? current : best;
}, null);

return [{
  json: {
    hasEvent: !!bestEvent,
    event: bestEvent,
    currentDate: currentDate,
    activeEvents: activeEvents.length,
    bestDiscount: bestEvent ? bestEvent.discount_percent : 0
  }
}];

const event = $json.event;
const discountPercent = event.discount_percent;

// Tính giá sau discount
const currentPrice = $json.body.currentPrice || $json.currentPrice || 0;
const displayPrice = Math.round(currentPrice * (1 - discountPercent / 100));

return [{
  json: {
    ...$json,
    eventDiscount: true,
    eventInfo: {
      name: event.name,
      discount_percent: discountPercent,
      start_date: event.start_date,
      end_date: event.end_date
    },
    display_price: displayPrice,
    discount_percent: discountPercent,
    isVIP: true,
    member_level: 'event'
  }
}];

return [{
  json: {
    ...$json,
    eventDiscount: false,
    eventInfo: null,
    display_price: $json.body.currentPrice || $json.currentPrice || 0,
    discount_percent: 0,
    isVIP: false,
    member_level: 'none'
  }
}];
